from dataclasses import dataclass
import anthropic

@dataclass
class ToolConfig:
    email_api_url: str
    payment_api_url: str
    search_api_url: str

TOOL_CONFIGS = {
    "dev": ToolConfig(
        email_api_url="http://localhost:1025",          # MailHog / Mailpit local
        payment_api_url="https://api.stripe.com/v1",   # Stripe test mode
        search_api_url="http://localhost:8080/search",  # local search stub
    ),
    "staging": ToolConfig(
        email_api_url="https://api.sendgrid.com/v3",   # real Sendgrid, test list
        payment_api_url="https://api.stripe.com/v1",   # Stripe test mode
        search_api_url="https://staging.search.myapp.com",
    ),
    "prod": ToolConfig(
        email_api_url="https://api.sendgrid.com/v3",   # real Sendgrid, real list
        payment_api_url="https://api.stripe.com/v1",   # Stripe live mode
        search_api_url="https://search.myapp.com",
    ),
}

def get_tool_config(env: str) -> ToolConfig:
    if env not in TOOL_CONFIGS:
        raise ValueError(f"Unknown environment: {env!r}")
    return TOOL_CONFIGS[env]
